package com.example.app.network.interceptor

import com.example.app.network.TokenProvider
import com.example.app.network.api.AuthApi
import com.example.app.network.api.RefreshTokenRequest
import kotlinx.coroutines.runBlocking
import okhttp3.Authenticator
import okhttp3.Request
import okhttp3.Response
import okhttp3.Route

class TokenRefreshAuthenticator(
    private val tokenProvider: TokenProvider,
    private val authApiProvider: () -> AuthApi
) : Authenticator {

    private val lock = Any()

    override fun authenticate(route: Route?, response: Response): Request? {
        // Don't retry if we've already tried refreshing
        if (responseCount(response) >= 2) {
            tokenProvider.clearTokens()
            return null
        }

        synchronized(lock) {
            val currentToken = tokenProvider.getAccessToken()
            val requestToken = response.request.header("Authorization")?.removePrefix("Bearer ")

            // Another thread already refreshed the token
            if (currentToken != null && currentToken != requestToken) {
                return response.request.newBuilder()
                    .header("Authorization", "Bearer $currentToken")
                    .build()
            }

            val refreshToken = tokenProvider.getRefreshToken() ?: run {
                tokenProvider.clearTokens()
                return null
            }

            val newTokens = runBlocking {
                try {
                    val refreshResponse = authApiProvider().refreshToken(
                        RefreshTokenRequest(refreshToken)
                    )
                    if (refreshResponse.isSuccessful) {
                        refreshResponse.body()?.data
                    } else {
                        null
                    }
                } catch (e: Exception) {
                    null
                }
            }

            return if (newTokens != null) {
                tokenProvider.saveTokens(newTokens.accessToken, newTokens.refreshToken)
                response.request.newBuilder()
                    .header("Authorization", "Bearer ${newTokens.accessToken}")
                    .build()
            } else {
                tokenProvider.clearTokens()
                null
            }
        }
    }

    private fun responseCount(response: Response): Int {
        var count = 1
        var prior = response.priorResponse
        while (prior != null) {
            count++
            prior = prior.priorResponse
        }
        return count
    }
}

