package com.example.app.network

import com.example.app.BuildConfig
import com.example.app.network.api.AuthApi
import com.example.app.network.api.UserApi
import com.example.app.network.interceptor.AuthInterceptor
import com.example.app.network.interceptor.TokenRefreshAuthenticator
import com.google.gson.GsonBuilder
import okhttp3.CertificatePinner
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {

    private lateinit var tokenProvider: TokenProvider
    private lateinit var environment: Environment

    private val gson by lazy {
        GsonBuilder()
            .setDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'")
            .create()
    }

    private val certificatePinner by lazy {
        CertificatePinner.Builder()
            // Production pins - replace with your actual certificate SHA-256 hashes
            .add(
                "api.example.com",
                "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA="
            )
            .add(
                "api.example.com",
                "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB="
            )
            .build()
    }

    private val loggingInterceptor by lazy {
        HttpLoggingInterceptor().apply {
            level = if (BuildConfig.DEBUG) {
                HttpLoggingInterceptor.Level.BODY
            } else {
                HttpLoggingInterceptor.Level.NONE
            }
            if (BuildConfig.DEBUG) {
                redactHeader("Authorization")
                redactHeader("Cookie")
            }
        }
    }

    private val authInterceptor by lazy {
        AuthInterceptor(tokenProvider)
    }

    private val tokenRefreshAuthenticator by lazy {
        TokenRefreshAuthenticator(
            tokenProvider = tokenProvider,
            authApiProvider = { authApi }
        )
    }

    // Separate OkHttpClient for auth API calls (no authenticator to avoid recursion)
    private val authOkHttpClient by lazy {
        val builder = OkHttpClient.Builder()
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            .addInterceptor(loggingInterceptor)

        // Apply certificate pinning for production
        if (environment == Environment.PRODUCTION) {
            builder.certificatePinner(certificatePinner)
        }

        builder.build()
    }

    private val okHttpClient by lazy {
        val builder = OkHttpClient.Builder()
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            .addInterceptor(authInterceptor)
            .addInterceptor(loggingInterceptor)
            .authenticator(tokenRefreshAuthenticator)

        // Apply certificate pinning for production
        if (environment == Environment.PRODUCTION) {
            builder.certificatePinner(certificatePinner)
        }

        builder.build()
    }

    private val retrofit by lazy {
        Retrofit.Builder()
            .baseUrl(environment.baseUrl)
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create(gson))
            .build()
    }

    private val authRetrofit by lazy {
        Retrofit.Builder()
            .baseUrl(environment.baseUrl)
            .client(authOkHttpClient)
            .addConverterFactory(GsonConverterFactory.create(gson))
            .build()
    }

    val userApi: UserApi by lazy {
        retrofit.create(UserApi::class.java)
    }

    private val authApi: AuthApi by lazy {
        authRetrofit.create(AuthApi::class.java)
    }

    fun initialize(
        tokenProvider: TokenProvider,
        environment: Environment = Environment.current()
    ) {
        this.tokenProvider = tokenProvider
        this.environment = environment
    }
}

