package com.example.app.network

import com.example.app.network.model.ApiResponse
import retrofit2.Response
import java.io.IOException

suspend fun <T> safeApiCall(
    apiCall: suspend () -> Response<ApiResponse<T>>
): NetworkResult<T> {
    return try {
        val response = apiCall()
        if (response.isSuccessful) {
            val body = response.body()
            if (body?.data != null) {
                NetworkResult.Success(body.data)
            } else {
                NetworkResult.Error(
                    code = response.code(),
                    message = body?.message ?: "Empty response body"
                )
            }
        } else {
            NetworkResult.Error(
                code = response.code(),
                message = response.errorBody()?.string() ?: response.message()
            )
        }
    } catch (e: IOException) {
        NetworkResult.Error(
            message = "Network error: ${e.localizedMessage}",
            exception = e
        )
    } catch (e: Exception) {
        NetworkResult.Error(
            message = "Unexpected error: ${e.localizedMessage}",
            exception = e
        )
    }
}

