    suspend fun getUsers(page: Int = 1, limit: Int = 20): NetworkResult<List<User>> {
        return safeApiCall { userApi.getUsers(page, limit) }
    }

    suspend fun getUserById(userId: Long): NetworkResult<User> {
        return safeApiCall { userApi.getUserById(userId) }
    }

    suspend fun getCurrentUser(): NetworkResult<User> {
        return safeApiCall { userApi.getCurrentUser() }
    }
}

