package com.example.app.ui

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.app.network.NetworkResult
import com.example.app.network.model.User
import com.example.app.network.repository.UserRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

data class UserListState(
    val users: List<User> = emptyList(),
    val isLoading: Boolean = false,
    val error: String? = null
)

data class UserProfileState(
    val user: User? = null,
    val isLoading: Boolean = false,
    val error: String? = null
)

class UserViewModel(
    private val userRepository: UserRepository = UserRepository()
) : ViewModel() {

    private val _userListState = MutableStateFlow(UserListState())
    val userListState: StateFlow<UserListState> = _userListState.asStateFlow()

    private val _profileState = MutableStateFlow(UserProfileState())
    val profileState: StateFlow<UserProfileState> = _profileState.asStateFlow()

    fun fetchUsers(page: Int = 1) {
        viewModelScope.launch {
            _userListState.value = _userListState.value.copy(isLoading = true, error = null)

            when (val result = userRepository.getUsers(page)) {
                is NetworkResult.Success -> {
                    _userListState.value = _userListState.value.copy(
                        users = result.data,
                        isLoading = false
                    )
                }
                is NetworkResult.Error -> {
                    _userListState.value = _userListState.value.copy(
                        isLoading = false,
                        error = result.message ?: "Unknown error"
                    )
                }
                is NetworkResult.Loading -> {
                    // Already handled above
                }
            }
        }
    }

    fun fetchUserProfile(userId: Long) {
        viewModelScope.launch {
            _profileState.value = _profileState.value.copy(isLoading = true, error = null)

            when (val result = userRepository.getUserById(userId)) {
                is NetworkResult.Success -> {
                    _profileState.value = _profileState.value.copy(
                        user = result.data,
                        isLoading = false
                    )
                }
                is NetworkResult.Error -> {
                    _profileState.value = _profileState.value.copy(
                        isLoading = false,
                        error = result.message ?: "Unknown error"
                    )
                }
                is NetworkResult.Loading -> {
                    // Already handled above
                }
            }
        }
    }

    fun fetchCurrentUser() {
        viewModelScope.launch {
            _profileState.value = _profileState.value.copy(isLoading = true, error = null)

            when (val result = userRepository.getCurrentUser()) {
                is NetworkResult.Success -> {
                    _profileState.value = _profileState.value.copy(
                        user = result.data,
                        isLoading = false
                    )
                }
                is NetworkResult.Error -> {
                    _profileState.value = _profileState.value.copy(
                        isLoading = false,
                        error = result.message ?: "Unknown error"
                    )
                }
                is NetworkResult.Loading -> {
                    // Already handled above
                }
            }
        }
    }
}